import Foundation
import Testing

@testable import FamilyCFO

/// Decodes the box's REAL /ai/* payloads through the generated types — pins
/// down whether a stuck AI-runtime screen is a decode failure or a view bug.
struct AIRuntimeDecodeTests {
    private func decode<T: Decodable>(_ type: T.Type, _ json: String) throws -> T {
        try JSONDecoder().decode(T.self, from: Data(json.utf8))
    }

    @Test func decodesLiveRuntimeStatus() throws {
        let status = try decode(
            Components.Schemas.AiRuntimeStatus.self,
            "{\"enabled\":true,\"provider\":\"vllm\",\"model\":\"Qwen/Qwen3.6-35B-A3B-FP8\",\"ready\":true,\"served_model\":\"Qwen/Qwen3.6-35B-A3B-FP8\",\"detail\":\"AI model 'Qwen/Qwen3.6-35B-A3B-FP8' is loaded and answering.\",\"vision_ready\":true,\"vision_model\":\"Qwen/Qwen3-VL-8B-Instruct-FP8\",\"vision_enabled\":true,\"loading_phase\":null,\"loading_detail\":null}")
        #expect(status.ready)
        #expect(status.servedModel == "Qwen/Qwen3.6-35B-A3B-FP8")
    }

    @Test func decodesLiveModelCatalog() throws {
        let catalog = try decode(
            Components.Schemas.AiModelCatalog.self,
            "{\"models\":[{\"id\":\"Qwen/Qwen2.5-7B-Instruct\",\"label\":\"Qwen2.5 7B — fast, light\",\"role\":\"main\",\"parameters_b\":7.0,\"est_memory_gb\":16.0,\"est_disk_gb\":15.0,\"tool_parser\":\"hermes\",\"supports_vision\":false,\"gated\":false,\"notes\":\"Quick answers on modest GPUs; weakest reasoning of the family.\",\"created_at\":null},{\"id\":\"Qwen/Qwen2.5-14B-Instruct\",\"label\":\"Qwen2.5 14B — balanced\",\"role\":\"main\",\"parameters_b\":14.0,\"est_memory_gb\":30.0,\"est_disk_gb\":28.0,\"tool_parser\":\"hermes\",\"supports_vision\":false,\"gated\":false,\"notes\":\"\",\"created_at\":null},{\"id\":\"Qwen/Qwen2.5-32B-Instruct\",\"label\":\"Qwen2.5 32B — recommended\",\"role\":\"main\",\"parameters_b\":32.0,\"est_memory_gb\":65.0,\"est_disk_gb\":62.0,\"tool_parser\":\"hermes\",\"supports_vision\":false,\"gated\":false,\"notes\":\"The default: strong reasoning and tool use.\",\"created_at\":null},{\"id\":\"Qwen/Qwen2.5-32B-Instruct-AWQ\",\"label\":\"Qwen2.5 32B AWQ — fast 4-bit (recommended on unified memory)\",\"role\":\"main\",\"parameters_b\":32.0,\"est_memory_gb\":22.0,\"est_disk_gb\":19.0,\"tool_parser\":\"hermes\",\"supports_vision\":false,\"gated\":false,\"notes\":\"Same model, 4-bit quantized: ~3-4x faster decode on bandwidth-limited hardware (GB10/DGX Spark class) with minimal quality loss.\",\"created_at\":null},{\"id\":\"Qwen/Qwen2.5-14B-Instruct-AWQ\",\"label\":\"Qwen2.5 14B AWQ — very fast 4-bit\",\"role\":\"main\",\"parameters_b\":14.0,\"est_memory_gb\":11.0,\"est_disk_gb\":9.0,\"tool_parser\":\"hermes\",\"supports_vision\":false,\"gated\":false,\"notes\":\"\",\"created_at\":null},{\"id\":\"Qwen/Qwen2.5-72B-Instruct-AWQ\",\"label\":\"Qwen2.5 72B AWQ — strongest proven chat for ~120GB boxes\",\"role\":\"main\",\"parameters_b\":72.0,\"est_memory_gb\":47.0,\"est_disk_gb\":41.0,\"tool_parser\":\"hermes\",\"supports_vision\":false,\"gated\":false,\"notes\":\"4-bit 72B: the strongest tool-calling chat model that fits ~120 GB unified memory, with room left for a large photo model beside it.\",\"created_at\":null},{\"id\":\"Qwen/Qwen2.5-72B-Instruct\",\"label\":\"Qwen2.5 72B — strongest\",\"role\":\"main\",\"parameters_b\":72.0,\"est_memory_gb\":145.0,\"est_disk_gb\":140.0,\"tool_parser\":\"hermes\",\"supports_vision\":false,\"gated\":false,\"notes\":\"Needs very large memory; consider only on 128GB+ unified or multi-GPU.\",\"created_at\":null},{\"id\":\"meta-llama/Llama-3.3-70B-Instruct\",\"label\":\"Llama 3.3 70B\",\"role\":\"main\",\"parameters_b\":70.0,\"est_memory_gb\":140.0,\"est_disk_gb\":132.0,\"tool_parser\":\"llama3_json\",\"supports_vision\":false,\"gated\":true,\"notes\":\"Gated on Hugging Face — requires HUGGING_FACE_HUB_TOKEN.\",\"created_at\":null},{\"id\":\"Qwen/Qwen3-VL-30B-A3B-Instruct-FP8\",\"label\":\"Qwen3-VL 30B-A3B FP8 — chat + photos in ONE model, fast\",\"role\":\"both\",\"parameters_b\":30.0,\"est_memory_gb\":33.0,\"est_disk_gb\":31.0,\"tool_parser\":\"hermes\",\"supports_vision\":true,\"gated\":false,\"notes\":\"MoE with ~3B active params: fast decode on bandwidth-limited boxes. Vision AND a tools-rendering template — a genuine all-in-one.\",\"created_at\":null},{\"id\":\"Qwen/Qwen3-VL-32B-Instruct-FP8\",\"label\":\"Qwen3-VL 32B FP8 — strongest all-in-one for ~120GB boxes\",\"role\":\"both\",\"parameters_b\":32.0,\"est_memory_gb\":35.0,\"est_disk_gb\":33.0,\"tool_parser\":\"hermes\",\"supports_vision\":true,\"gated\":false,\"notes\":\"Dense 32B, vision + tools in one container. Slower than the 30B-A3B MoE but stronger per token.\",\"created_at\":null},{\"id\":\"Qwen/Qwen3-VL-8B-Instruct\",\"label\":\"Qwen3-VL 8B — light all-in-one\",\"role\":\"both\",\"parameters_b\":8.0,\"est_memory_gb\":17.0,\"est_disk_gb\":16.0,\"tool_parser\":\"hermes\",\"supports_vision\":true,\"gated\":false,\"notes\":\"Small single-model option: vision + tools on modest hardware.\",\"created_at\":null},{\"id\":\"Qwen/Qwen3-VL-8B-Instruct-FP8\",\"label\":\"Qwen3-VL 8B FP8 — modern photo describer\",\"role\":\"both\",\"parameters_b\":8.0,\"est_memory_gb\":9.0,\"est_disk_gb\":9.0,\"tool_parser\":\"hermes\",\"supports_vision\":true,\"gated\":false,\"notes\":\"FP8 half-memory build of the 8B: the best photo describer that fits BESIDE a large chat model (~9 GB); also works as a light all-in-one.\",\"created_at\":null},{\"id\":\"Qwen/Qwen2.5-VL-32B-Instruct\",\"label\":\"Qwen2.5-VL 32B — photos (no tool calling)\",\"role\":\"both\",\"parameters_b\":33.0,\"est_memory_gb\":70.0,\"est_disk_gb\":66.0,\"tool_parser\":null,\"supports_vision\":true,\"gated\":false,\"notes\":\"Cannot call the financial tools (the VL chat template omits them) — best as the photo model; as the chat model, answers fall back to deterministic snapshots.\",\"created_at\":null},{\"id\":\"Qwen/Qwen2.5-VL-72B-Instruct\",\"label\":\"Qwen2.5-VL 72B — strongest photos (no tool calling)\",\"role\":\"both\",\"parameters_b\":72.0,\"est_memory_gb\":145.0,\"est_disk_gb\":140.0,\"tool_parser\":null,\"supports_vision\":true,\"gated\":false,\"notes\":\"Cannot call the financial tools — best as the photo model. Needs very large memory (multi-GPU or 160GB+ unified).\",\"created_at\":null},{\"id\":\"Qwen/Qwen2.5-VL-72B-Instruct-AWQ\",\"label\":\"Qwen2.5-VL 72B AWQ — biggest photo model for ~120GB boxes\",\"role\":\"both\",\"parameters_b\":72.0,\"est_memory_gb\":45.0,\"est_disk_gb\":41.0,\"tool_parser\":null,\"supports_vision\":true,\"gated\":false,\"notes\":\"4-bit quantized: 72B-class vision in ~45 GB — the strongest PHOTO model on GB10-class hardware. Cannot call the financial tools, so pair it with a tool-calling chat model.\",\"created_at\":null},{\"id\":\"Qwen/Qwen2.5-VL-7B-Instruct\",\"label\":\"Qwen2.5-VL 7B — vision describer\",\"role\":\"vision\",\"parameters_b\":7.0,\"est_memory_gb\":16.0,\"est_disk_gb\":16.0,\"tool_parser\":null,\"supports_vision\":true,\"gated\":false,\"notes\":\"The default photo describer.\",\"created_at\":null},{\"id\":\"Qwen/Qwen2.5-VL-3B-Instruct\",\"label\":\"Qwen2.5-VL 3B — lightest describer\",\"role\":\"vision\",\"parameters_b\":3.0,\"est_memory_gb\":8.0,\"est_disk_gb\":7.0,\"tool_parser\":null,\"supports_vision\":true,\"gated\":false,\"notes\":\"Lower quality transcription; use when memory is tight.\",\"created_at\":null}]}")
        #expect(catalog.models.count >= 10)
    }

    @Test func decodesLiveHardwareProfile() throws {
        let hardware = try decode(
            Components.Schemas.AiHardwareProfile.self,
            "{\"gpu_memory_gb\":null,\"system_memory_gb\":121.7,\"disk_free_gb\":2144.3,\"source\":\"system\"}")
        #expect(hardware.systemMemoryGb == 121.7)
    }
}
